import com.mawelly.blitzmath.localization.AppLanguage

data class MathQuote(
    val quoteTR: String,
    val quoteEN: String,
    val quoteES: String,
    val quoteDE: String,
    val quoteFR: String,
    val quoteIT: String,
    val quotePT: String,
    val quoteHI: String,
    val quoteZH: String,
    val quoteRU: String,
    val author: String
) {
    fun getQuote(language: AppLanguage): String {
        return when (language) {
            AppLanguage.TURKISH -> quoteTR
            AppLanguage.ENGLISH -> quoteEN
            AppLanguage.SPANISH -> quoteES
            AppLanguage.GERMAN -> quoteDE
            AppLanguage.FRENCH -> quoteFR
            AppLanguage.ITALIAN -> quoteIT
            AppLanguage.PORTUGUESE -> quotePT
            AppLanguage.HINDI -> quoteHI
            AppLanguage.CHINESE -> quoteZH
            AppLanguage.RUSSIAN -> quoteRU
        }
    }
}

